Here’s a simple Python example using a dictionary to track monthly eco-anxiety scores for users:

python
class EcoAnxietyTracker:
    def __init__(self):
        self.users = {}

    def add_user(self, user_id):
        self.users[user_id] = []

    def record_score(self, user_id, score):
        if user_id in self.users:
            self.users[user_id].append(score)
        else:
            raise ValueError("User not found.")

    def get_avg_score(self, user_id):
        if user_id in self.users and self.users[user_id]:
            return sum(self.users[user_id]) / len(self.users[user_id])
        return None

# Example usage
tracker = EcoAnxietyTracker()
tracker.add_user("user123")
tracker.record_score("user123", 7)
tracker.record_score("user123", 5)
print(tracker.get_avg_score("user123"))  # Output: 6.0
